def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 15):
            weight = 1 / (j ** 2)
            term = (ratio ** j) * weight
            if j % 3 == 0:
                term *= 1.3
            elif j % 2 == 0:
                term *= 1.1
            else:
                term *= 0.9
            score += term
        remaining = capacity - item
        if remaining < 0.05 * capacity:
            score *= 2.5
        elif remaining < 0.2 * capacity:
            score *= 1.5
        else:
            for k in range(1, 5):
                threshold = k * 0.15 * capacity
                if remaining > threshold:
                    score *= 0.85 ** k
                else:
                    break
        if item > 0.6 * capacity:
            score += np.log1p(item) * 1.2
        if i > 0:
            prev_capacity = bins[i-1]
            if prev_capacity > capacity:
                score *= 1.15
            elif prev_capacity == capacity:
                score *= 1.05
            else:
                score *= 0.9
        if i < n - 1:
            next_capacity = bins[i+1]
            if next_capacity < capacity:
                score *= 1.1
            else:
                score *= 0.95
        if i % 2 == 0:
            score += 0.05 * np.cos(i + item)
        else:
            score += 0.03 * np.sin(i * item)
        if score < 0.2:
            score += 0.1 * (remaining / capacity)
        if score > 3:
            score *= 0.8
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        max_priority = 1.0
    else:
        max_priority = np.max(finite_priorities)
    for i in range(n):
        if priorities[i] == np.inf:
            priorities[i] = max_priority * 4
    for i in range(n):
        if priorities[i] < 0.15:
            priorities[i] += 0.07 * np.sin(i * 0.5 + item)
        if i % 5 == 0:
            priorities[i] *= 1.05
    return priorities
